#include <bits/stdc++.h>
using namespace std;

// Structure to represent each node of the binary tree
struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    // Constructor to initialize node with value
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    // Helper function to traverse the tree and count nodes
    void inorder(TreeNode* root, int &count) {
        // If current node is NULL, stop processing
        if (root == NULL) {
            return;
        }
        // Increment count for current node
        count++;
        // Recursively count nodes in the left subtree
        inorder(root->left, count);
        // Recursively count nodes in the right subtree
        inorder(root->right, count);
    }

    // Function to count total number of nodes in the binary tree
    int countNodes(TreeNode* root) {
        // If tree is empty, return 0
        if (root == NULL) {
            return 0;
        }
        // Variable to store node count
        int count = 0;
        // Perform inorder traversal to count nodes
        inorder(root, count);
        // Return total number of nodes
        return count;
    }
};

int main() {
    // Create binary tree
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    root->left->left = new TreeNode(4);
    root->left->right = new TreeNode(5);
    root->right->left = new TreeNode(6);

    // Create solution object
    Solution sol;

    // Get total number of nodes
    int totalNodes = sol.countNodes(root);

    // Output the result
    cout << "Total number of nodes in the Complete Binary Tree: " << totalNodes << endl;

    return 0;
}

